#include<bits/stdc++.h>
using namespace std;

int s[500005];
int dis[500005], minn = 1e8;
int sfind(int x) {
	if (x == s[x])	return x;
	int root = sfind(s[x]);
	dis[x] += dis[s[x]];
    s[x] = root;
	return root ;
}
void smerge(int i, int x) {
	int fi = sfind(i);
	int fx = sfind(x);
	if (fi == fx) {
		minn = min(minn, dis[i] - dis[x] + 1);
	}
	s[fx] = fi;
	dis[fx] = dis[i] + 1 - dis[x];
}
int main() {
	int n;
	cin >> n;
    for (int i = 1; i <= n; i++) s[i] = i;
	for (int i = 1; i <= n; i++) {
		int x;
		cin >> x;
        smerge(i, x);
	}
	cout << minn;

	return 0;
}
